import{_ as t,o as l,c as o,ae as i}from"./chunks/framework.Czhw_PXq.js";const c=JSON.parse('{"title":"《让时间陪你慢慢变富》第5讲：定投是普通人必需的选择","description":"为什么普通人必须定投？时间成本分析与李笑来的定投经历","frontmatter":{"title":"《让时间陪你慢慢变富》第5讲：定投是普通人必需的选择","description":"为什么普通人必须定投？时间成本分析与李笑来的定投经历","pubDate":"2026-05-16"},"headers":[],"relativePath":"posts/lixiaolai-dt-05.md","filePath":"posts/lixiaolai-dt-05.md"}'),e={name:"posts/lixiaolai-dt-05.md"};function r(n,a,s,p,h,d){return l(),o("div",null,[...a[0]||(a[0]=[i('<h1 id="第5讲-定投是普通人必需的选择" tabindex="-1">第5讲：定投是普通人必需的选择 <a class="header-anchor" href="#第5讲-定投是普通人必需的选择" aria-label="Permalink to &quot;第5讲：定投是普通人必需的选择&quot;">​</a></h1><blockquote><p>在当前这个时代里，理论上，每个普通人都有实现财富自由的机会。</p></blockquote><h2 id="引言-决定富有的三个条件" tabindex="-1">引言：决定富有的三个条件 <a class="header-anchor" href="#引言-决定富有的三个条件" aria-label="Permalink to &quot;引言：决定富有的三个条件&quot;">​</a></h2><p>被认为是20世纪最有影响力的经济学家之一的富兰克·奈特（Frank H. Knight）有个著名的观点：</p><blockquote><p><strong>决定一个人富有的三个条件，一是出身，二是运气，三是努力；而这三者之中，努力是最微不足道的。</strong></p></blockquote><p>当然，这并不是说努力就不重要了，因为相对成功可以靠努力，巨大成功只能靠运气——谁都知道运气是普通人无法左右的；而出身（或者联姻）么，更不是普通人可以仰仗的因素。</p><h2 id="第一部分-时间的真相" tabindex="-1">第一部分：时间的真相 <a class="header-anchor" href="#第一部分-时间的真相" aria-label="Permalink to &quot;第一部分：时间的真相&quot;">​</a></h2><h3 id="人生时间的分配" tabindex="-1">人生时间的分配 <a class="header-anchor" href="#人生时间的分配" aria-label="Permalink to &quot;人生时间的分配&quot;">​</a></h3><p>如果按照我们每个人的平均寿命为<strong>78年</strong>计算的话：</p><table tabindex="0"><thead><tr><th>活动</th><th>时间</th></tr></thead><tbody><tr><td>睡觉</td><td>28.3年</td></tr><tr><td>工作</td><td>10.5年</td></tr><tr><td>社交媒体</td><td>9年</td></tr><tr><td>做家务</td><td>6年</td></tr><tr><td>吃喝</td><td>4年</td></tr><tr><td>接受教育</td><td>3.5年</td></tr><tr><td>化妆打扮</td><td>3年</td></tr><tr><td>购物</td><td>2.5年</td></tr><tr><td>照顾小孩</td><td>1.5年</td></tr><tr><td>路上</td><td>1.3年</td></tr><tr><td><strong>剩余自由时间</strong></td><td><strong>约9年</strong></td></tr></tbody></table><p>仅仅<strong>9年</strong>！</p><h3 id="什么叫真拼" tabindex="-1">什么叫真拼 <a class="header-anchor" href="#什么叫真拼" aria-label="Permalink to &quot;什么叫真拼&quot;">​</a></h3><p>什么叫拼？如果别人一天工作8小时，你一天工作10小时，你的确比别人拼；但事实上，你只不过是比别人多拼了2小时而已——也就是说，只有在那2小时里，你真的在拼。</p><p>什么叫真拼？就是所有人其实都只有9年可以自由支配的时间，你却把那9年时间全部用来去拼。可是，就算全部用来去拼，加起来也不过是9年时间。</p><p>上面的数据中，还没有扣除掉你可能生病的时间、你可能情绪低落的时间，也没有考虑到各种各样稀奇古怪的意外事件的发生！</p><h2 id="第二部分-李笑来的-拼-经历" tabindex="-1">第二部分：李笑来的&quot;拼&quot;经历 <a class="header-anchor" href="#第二部分-李笑来的-拼-经历" aria-label="Permalink to &quot;第二部分：李笑来的&quot;拼&quot;经历&quot;">​</a></h2><h3 id="_24年没有节假日" tabindex="-1">24年没有节假日 <a class="header-anchor" href="#_24年没有节假日" aria-label="Permalink to &quot;24年没有节假日&quot;">​</a></h3><p>年轻的时候，李笑来和其他年轻人一样，是非常拼的。</p><p>刚从学校毕业出来做销售的时候，他曾经可以一周内6个夜晚睡在火车上，早上下车找个洗澡的地方换衣服，然后做一天的培训工作，而后晚上踏上火车睡上一觉，醒来后就在另外一个城市里继续工作……</p><p>认识他很多年的人都知道，李笑来是不过节假日的。这是为什么呢？</p><p>因为在1995年大学快毕业的时候，有一天他突然想，怎么节假日这么多？</p><blockquote><p><strong>一年365天，法定节假日竟然有115个！</strong></p></blockquote><p>也就是说，一年的1/3被&quot;休息&quot;掉了！总觉得哪里不对。后来注意到&quot;法定&quot;两个字，于是恍然大悟——哦，这个法定节假日是用来限制用工企业的，到了法定节假日，企业不让人休息，那是违法的！</p><p>也就是说，这个法定节假日不是限制个人的——没有任何法律可以说：&quot;今天是法定节假日，你不休息，你违法了！&quot;</p><p>于是，他就决定，从此之后，法定节假日与李笑来无关！</p><p>从1995年开始到2019年，24年过去了——他就是没有周六周日、没有元旦春节，每天该干吗就干吗地走过来的。</p><h3 id="自己理发省时间" tabindex="-1">自己理发省时间 <a class="header-anchor" href="#自己理发省时间" aria-label="Permalink to &quot;自己理发省时间&quot;">​</a></h3><p>大约十年前，他发现&quot;在意自己的发型&quot;是时间成本非常高的习惯。每个月都要花上一两个小时去理发，动不动还要在理发店等很久，于是，他决定以后自己理发。</p><p>一把飞利浦电动理发器真的很便宜，三百多块钱，能用好几年。于是你就看到了他随后十几年里的固定发型，3毫米圆头板寸。这很简单，基本上就是在某次淋浴之前，用推子在镜子前自己三五分钟搞定。</p><h3 id="数据令人沮丧" tabindex="-1">数据令人沮丧 <a class="header-anchor" href="#数据令人沮丧" aria-label="Permalink to &quot;数据令人沮丧&quot;">​</a></h3><p>你看，他对自己下手这么狠，那么结果是什么呢？</p><p><strong>24年没有节假日的有效工作时间：</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>24年 × 115天 × 4小时 = 11,040小时</span></span></code></pre></div><p>相当于多少年？</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>11,040 ÷ (365 × 24) = 1.26年</span></span></code></pre></div><p>你看，对自己下手这么狠，结果不过是相对于&quot;其他真的很拼的人们&quot;多拼了**14%**而已。</p><p><strong>自己理发10年节省的时间：</strong></p><ul><li>每月1次，每次平均1.5小时</li><li>一年下来就是18个小时</li><li>10年下来，就是180个小时</li></ul><p>用了这么大的力气，只不过是比所有人增加了**2.28‰**而已啊！</p><h2 id="第三部分-为什么普通人必须定投" tabindex="-1">第三部分：为什么普通人必须定投 <a class="header-anchor" href="#第三部分-为什么普通人必须定投" aria-label="Permalink to &quot;第三部分：为什么普通人必须定投&quot;">​</a></h2><h3 id="没有投资等于没有拼过" tabindex="-1">没有投资等于没有拼过 <a class="header-anchor" href="#没有投资等于没有拼过" aria-label="Permalink to &quot;没有投资等于没有拼过&quot;">​</a></h3><p>这就解释了为什么普通人必须定投，或者反过来说，<strong>定投就是普通人的必需</strong>。</p><p>因为没有投资，作为普通人的你就相当于从来没有拼过！</p><h3 id="投资的本质" tabindex="-1">投资的本质 <a class="header-anchor" href="#投资的本质" aria-label="Permalink to &quot;投资的本质&quot;">​</a></h3><p>投资的本质是什么？</p><blockquote><p><strong>投资的本质就是用你的钱去帮你赚钱——而钱这个东西，它是不休息的，它一年365天，每天24小时，在投资正确的前提下，它都在为你工作。</strong></p></blockquote><p>请问，你的汗水和努力怎么跟它比拼？</p><h3 id="巴菲特的例子" tabindex="-1">巴菲特的例子 <a class="header-anchor" href="#巴菲特的例子" aria-label="Permalink to &quot;巴菲特的例子&quot;">​</a></h3><p>我们之所以很羡慕沃伦·巴菲特就是因为以下的事实：</p><ul><li>巴菲特1930年出生，11岁买了他人生第一支股票</li><li>到现在2019年，已经<strong>78年</strong>了！</li></ul><p>别人平均寿命78岁，其中只有9年是可以用来额外打拼的所谓有效寿命，可是巴菲特呢？</p><p>巴菲特的钱已经帮着他78年每年365天、每天24小时地拼着……</p><p>这相当于说，不从事任何投资活动的普通人就算活上<strong>8辈子</strong>也追不上他！</p><p>因为：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>78 ÷ 9 = 8.6667</span></span></code></pre></div><p>而且，巴菲特老爷子的身体还很健康，还会继续活下去；更为关键的是，他已经把自己的投资活动做成了一个企业并且上市了（伯克希尔·哈撒韦公司）——也就是说，就算巴菲特老爷子去世了，这家上市公司的钱还在毫不间歇地干活……</p><p>很惊人！</p><h2 id="第四部分-李笑来的定投经历" tabindex="-1">第四部分：李笑来的定投经历 <a class="header-anchor" href="#第四部分-李笑来的定投经历" aria-label="Permalink to &quot;第四部分：李笑来的定投经历&quot;">​</a></h2><h3 id="普通人的起点" tabindex="-1">普通人的起点 <a class="header-anchor" href="#普通人的起点" aria-label="Permalink to &quot;普通人的起点&quot;">​</a></h3><p>李笑来自认是个普通人——起码，连出身都非常普通。</p><ul><li>出生在东北黑龙江省海林县</li><li>父亲是一中英语老师，母亲是兽医站兽医</li><li>第一年高考落榜，第二年考上三本大学（长春大学）</li><li>毕业后从销售做起</li></ul><h3 id="新东方的日子" tabindex="-1">新东方的日子 <a class="header-anchor" href="#新东方的日子" aria-label="Permalink to &quot;新东方的日子&quot;">​</a></h3><p>三十岁之后，生活渐渐稳定下来——普通人不都是这样的吗？</p><p>在新东方工作的他，虽然每年税后收入差不多五六十万，可完全没有人们普遍以为的这个薪资水平的所谓&quot;白领&quot;生活。</p><ul><li>生病的父亲动不动就住在医院里</li><li>大多数收入实际上等于是&quot;直接寄到医院里&quot;</li><li>和老婆两个人在北京每年的花销不超过15万人民币</li></ul><p>2005年，父亲去世。母亲说，&quot;笑来，我知道这些年你太累了，现在你自由了……&quot;</p><p>他自由了吗？并没有。</p><ul><li>没有买房（收入都被医院拿走了）</li><li>没有买车（在工作场所附近租房子）</li><li>没有养孩子（觉得自己活不明白）</li><li>攒钱还是非常难</li></ul><h3 id="关键的转变" tabindex="-1">关键的转变 <a class="header-anchor" href="#关键的转变" aria-label="Permalink to &quot;关键的转变&quot;">​</a></h3><p>到了2007年，他决定离开新东方。主要原因是因为当时的他已经有了比较稳定的稿费收入。</p><p>他想明白了一个道理：</p><blockquote><p><strong>我必须想办法把同一份自己的时间卖出许多次——写长销书就是这样的方法。</strong></p></blockquote><p>后来，他把这个方法论写成了另外一本书，《财富自由之路》。</p><h3 id="定投改变命运" tabindex="-1">定投改变命运 <a class="header-anchor" href="#定投改变命运" aria-label="Permalink to &quot;定投改变命运&quot;">​</a></h3><p>2011年的春天，他误打误撞进入了投资领域。转眼8年过去，他做得很好，成绩相当不错。</p><p>日子终于变了，终于实实在在地不普通了。</p><p>毫无疑问，最终，是<strong>定投改变了他的命运</strong>。</p><p>过去8年的投资经历，使得他越来越清楚地看到一个事实：</p><blockquote><p><strong>在当前这个时代里，理论上，每个普通人都有实现财富自由的机会。</strong></p></blockquote><h2 id="第五部分-给普通人的建议" tabindex="-1">第五部分：给普通人的建议 <a class="header-anchor" href="#第五部分-给普通人的建议" aria-label="Permalink to &quot;第五部分：给普通人的建议&quot;">​</a></h2><h3 id="赚钱是硬本事" tabindex="-1">赚钱是硬本事 <a class="header-anchor" href="#赚钱是硬本事" aria-label="Permalink to &quot;赚钱是硬本事&quot;">​</a></h3><p>赚钱，绝对是硬本事。可遗憾的是，它对绝大多数普通人来说，就是一种：</p><ul><li>父母不会</li><li>学校不教</li><li>整个社会还要妖魔化它的技能</li></ul><p>没有人能够清楚地解释这到底是为什么。</p><h3 id="定投是最简单的方法" tabindex="-1">定投是最简单的方法 <a class="header-anchor" href="#定投是最简单的方法" aria-label="Permalink to &quot;定投是最简单的方法&quot;">​</a></h3><p>然而，随着时间的推移，他对这个事实越来越笃定：</p><p><strong>定投是最简单、最有效、最适合普通人的投资方法。</strong></p><p>它不仅给出一个清楚的方法论，并且还提供一个完整的践行通路：</p><ul><li>不做不要读</li><li>读了就必须做</li><li>做了不会马上有结果</li><li>长期做必然有好结果</li></ul><h3 id="人至践则无敌" tabindex="-1">人至践则无敌 <a class="header-anchor" href="#人至践则无敌" aria-label="Permalink to &quot;人至践则无敌&quot;">​</a></h3><blockquote><p><strong>人至践则无敌！</strong></p><p>不是犯贱的贱，而是践行的践。</p></blockquote><p>一切学习的结果都建立在践行的基础上。没有践行的话，一个人只是学到了而已，实际上却没有做到——也根本没有机会做到。</p><p>定投策略的神奇之处在于：</p><ol><li>它使得采用它的投资者必须践行</li><li>它动作单一，所以相对很容易践行</li><li>它本身提供了一个简单、长期、稳定的投资教学环境</li></ol><h2 id="第六部分-开始你的定投之旅" tabindex="-1">第六部分：开始你的定投之旅 <a class="header-anchor" href="#第六部分-开始你的定投之旅" aria-label="Permalink to &quot;第六部分：开始你的定投之旅&quot;">​</a></h2><h3 id="第一步-选择标的" tabindex="-1">第一步：选择标的 <a class="header-anchor" href="#第一步-选择标的" aria-label="Permalink to &quot;第一步：选择标的&quot;">​</a></h3><p>选择市场上最被看好的标的：</p><ul><li>市值大</li><li>流动性好</li><li>长期看涨</li></ul><h3 id="第二步-设定计划" tabindex="-1">第二步：设定计划 <a class="header-anchor" href="#第二步-设定计划" aria-label="Permalink to &quot;第二步：设定计划&quot;">​</a></h3><p>确定定投四要素：</p><ul><li><strong>长期</strong>：至少7-10年</li><li><strong>定期</strong>：每月或每周</li><li><strong>定额</strong>：固定金额</li><li><strong>标的</strong>：已选定</li></ul><h3 id="第三步-自动执行" tabindex="-1">第三步：自动执行 <a class="header-anchor" href="#第三步-自动执行" aria-label="Permalink to &quot;第三步：自动执行&quot;">​</a></h3><p>设置自动扣款，避免情绪干扰。</p><h3 id="第四步-长期持有" tabindex="-1">第四步：长期持有 <a class="header-anchor" href="#第四步-长期持有" aria-label="Permalink to &quot;第四步：长期持有&quot;">​</a></h3><p>相信时间的力量，让时间陪你慢慢变富。</p><h3 id="第五步-加入社区" tabindex="-1">第五步：加入社区 <a class="header-anchor" href="#第五步-加入社区" aria-label="Permalink to &quot;第五步：加入社区&quot;">​</a></h3><p>找到同类，共同成长，不孤单。</p><h2 id="本章总结" tabindex="-1">本章总结 <a class="header-anchor" href="#本章总结" aria-label="Permalink to &quot;本章总结&quot;">​</a></h2><h3 id="核心要点回顾" tabindex="-1">核心要点回顾 <a class="header-anchor" href="#核心要点回顾" aria-label="Permalink to &quot;核心要点回顾&quot;">​</a></h3><ol><li><strong>时间有限</strong>：普通人一生只有9年可自由支配的时间</li><li><strong>努力有限</strong>：再拼也只能增加14%的有效时间</li><li><strong>投资无限</strong>：钱可以24小时不间断工作</li><li><strong>定投必需</strong>：普通人实现财富自由的最佳途径</li><li><strong>践行第一</strong>：不做不要读，读了就必须做</li></ol><h3 id="关键概念" tabindex="-1">关键概念 <a class="header-anchor" href="#关键概念" aria-label="Permalink to &quot;关键概念&quot;">​</a></h3><ul><li><strong>有效寿命</strong>：可自由支配的时间，约9年</li><li><strong>钱的工作</strong>：365天×24小时不间断</li><li><strong>定投改变命运</strong>：李笑来的亲身经历</li><li><strong>人至践则无敌</strong>：践行是学习的唯一目的</li></ul><h3 id="行动清单" tabindex="-1">行动清单 <a class="header-anchor" href="#行动清单" aria-label="Permalink to &quot;行动清单&quot;">​</a></h3><ul><li>[ ] 选择定投标的</li><li>[ ] 设定定投计划</li><li>[ ] 开通自动扣款</li><li>[ ] 加入定投社区</li><li>[ ] 开始践行，长期持有</li></ul><h3 id="结语" tabindex="-1">结语 <a class="header-anchor" href="#结语" aria-label="Permalink to &quot;结语&quot;">​</a></h3><blockquote><p><strong>让时间陪你慢慢变富。</strong></p></blockquote><p>这不是一句口号，而是一个可以实现的承诺。</p><p>只要你：</p><ul><li>选择正确的标的</li><li>坚持定投策略</li><li>相信时间的力量</li></ul><p>时间就会成为你的朋友，陪你慢慢变富。</p><hr><p><em>本文基于李笑来《让时间陪你慢慢变富》第10章及结语整理。</em></p>',122)])])}const b=t(e,[["render",r]]);export{c as __pageData,b as default};
